Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <unordered_map>

using namespace std;

int main() {
    ifstream file("input.txt");
    if (!file.is_open()) {
        cerr << "Error: Could not open file" << endl;
        return 1;
    }

    unordered_map<string, int> wordCount;

    string line;
    while (getline(file, line)) {
        string word = "";
        size_t found = line.find("your_word_here");
        if (found != string::npos) {
            word = line.substr(0, found);
            ++wordCount[word];
        }
    }

    for (const auto& entry : wordCount) {
        cout << entry.first << ": " << entry.second << endl;
    }

    return 0;
}
```

Replace `input.txt` with the name of your text file. Replace `"your_word_here"` with the specific word you want to count. This program uses an unordered map to count the occurrences of each word. The output will show the word and its count in the format `word: count`.

