from collections import deque

class QueueUsingStacks:
    def __init__(self):
        self.queue = []
        self.stack1 = deque()
        self.stack2 = deque()

    def is_empty(self):
        return not self.queue and not self.stack1 and not self.stack2

    def push(self, item):
        self.queue.append(item)
        if not self.stack1:
            self.stack1.append(item)
        elif item > self.stack1[-1]:
            self.stack1.pop()
            self.stack1.append(item)

    def pop(self):
        if not self.is_empty():
            item = self.queue.pop(0)
            if item < self.stack1[-1]:
                self.stack1.pop()
            return item
        return None

    def peek(self):
        if not self.is_empty():
            return self.queue[0]
        for i in range(len(self.stack1)):
            if self.stack1[i] > self.queue[-1]:
                return self.stack1[i]
        return None
